var doc = uiapp.ActiveUIDocument.Document;
var view = uiapp.ActiveUIDocument.ActiveView;
var selIds = uiapp.ActiveUIDocument.Selection.GetElementIds().ToList();
if (selIds.Count == 0) return new { bbox = (object)null, note = "no selection" };
var boxes = selIds.Select(id => doc.GetElement(id).get_BoundingBox(view)).Where(b => b != null).ToList();
if (boxes.Count == 0) return new { bbox = (object)null, note = "no bounding box for selected elements in this view" };
var min = new XYZ(boxes.Min(b => b.Min.X), boxes.Min(b => b.Min.Y), boxes.Min(b => b.Min.Z));
var max = new XYZ(boxes.Max(b => b.Max.X), boxes.Max(b => b.Max.Y), boxes.Max(b => b.Max.Z));
return new { selected = selIds.Count, min = new { x = min.X, y = min.Y, z = min.Z }, max = new { x = max.X, y = max.Y, z = max.Z } };
